  1→/**
  2→ * Intent Submission with DPoP Thumbprint Binding
  3→ *
  4→ * OAuth 2.1 RAR+DPoP intent submission endpoint.
  5→ * Validates authorization_details with type "brain_action" and dpop_jwk_thumbprint,
  6→ * creates intent record, triggers evaluation pipeline.
  7→ *
  8→ * Pure validation functions + HTTP handler factory.
  9→ */
 10→
 11→import { RecordId } from "surrealdb";
 12→import type { BrainAction } from "./types";
 13→import type { ActionSpec } from "../intent/types";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { jsonError, jsonResponse } from "../http/response";
 16→import { logError, logInfo } from "../http/observability";
 17→import { createIntent, updateIntentStatus } from "../intent/intent-queries";
 18→import { evaluateIntent, createLlmEvaluator } from "../intent/authorizer";
 19→import { routeByRisk } from "../intent/risk-router";
 20→import {
 21→  checkIdentityAllowed,
 22→  type LookupIdentity,
 23→  type LookupManager,
 24→} from "./identity-lifecycle";
 25→
 26→// ---------------------------------------------------------------------------
 27→// Input Types
 28→// ---------------------------------------------------------------------------
 29→
 30→export type IntentSubmissionInput = {
 31→  workspace_id: string;
 32→  identity_id: string;
 33→  authorization_details: BrainAction[];
 34→  dpop_jwk_thumbprint: string;
 35→  goal: string;
 36→  reasoning: string;
 37→  priority?: number;
 38→};
 39→
 40→type ValidationResult =
 41→  | { valid: true; data: IntentSubmissionInput }
 42→  | { valid: false; error: string };
 43→
 44→// ---------------------------------------------------------------------------
 45→// Pure Validation
 46→// ---------------------------------------------------------------------------
 47→
 48→const LOW_RISK_ACTIONS = new Set(["read", "list", "get", "search", "query"]);
 49→
 50→export function validateIntentSubmission(input: unknown): ValidationResult {
 51→  if (!input || typeof input !== "object") {
 52→    return { valid: false, error: "Request body must be a non-null object" };
 53→  }
 54→
 55→  const body = input as Record<string, unknown>;
 56→
 57→  // Required string fields
 58→  const requiredStrings = ["workspace_id", "identity_id", "goal", "reasoning"] as const;
 59→  for (const field of requiredStrings) {
 60→    if (typeof body[field] !== "string" || (body[field] as string).trim().length === 0) {
 61→      return { valid: false, error: `${field} is required and must be a non-empty string` };
 62→    }
 63→  }
 64→
 65→  // dpop_jwk_thumbprint
 66→  if (typeof body.dpop_jwk_thumbprint !== "string" || (body.dpop_jwk_thumbprint as string).trim().length === 0) {
 67→    return { valid: false, error: "dpop_jwk_thumbprint is required and must be a non-empty string" };
 68→  }
 69→
 70→  // authorization_details
 71→  if (!Array.isArray(body.authorization_details)) {
 72→    return { valid: false, error: "authorization_details is required and must be an array" };
 73→  }
 74→
 75→  if (body.authorization_details.length === 0) {
 76→    return { valid: false, error: "authorization_details must contain at least one entry" };
 77→  }
 78→
 79→  for (let i = 0; i < body.authorization_details.length; i++) {
 80→    const entry = body.authorization_details[i] as Record<string, unknown>;
 81→    const validationError = validateBrainActionEntry(entry, i);
 82→    if (validationError) {
 83→      return { valid: false, error: validationError };
 84→    }
 85→  }
 86→
 87→  // Optional priority
 88→  const priority = typeof body.priority === "number" ? body.priority : undefined;
 89→
 90→  return {
 91→    valid: true,
 92→    data: {
 93→      workspace_id: (body.workspace_id as string).trim(),
 94→      identity_id: (body.identity_id as string).trim(),
 95→      authorization_details: body.authorization_details as BrainAction[],
 96→      dpop_jwk_thumbprint: (body.dpop_jwk_thumbprint as string).trim(),
 97→      goal: (body.goal as string).trim(),
 98→      reasoning: (body.reasoning as string).trim(),
 99→      ...(priority !== undefined ? { priority } : {}),
100→    },
101→  };
102→}
103→
104→export function validateBrainActionEntry(entry: Record<string, unknown>, index: number): string | undefined {
105→  if (!entry || typeof entry !== "object") {
106→    return `authorization_details[${index}] must be an object`;
107→  }
108→
109→  if (entry.type !== "brain_action") {
110→    return `authorization_details[${index}].type must be "brain_action"`;
111→  }
112→
113→  if (typeof entry.action !== "string" || entry.action.trim().length === 0) {
114→    return `authorization_details[${index}].action is required and must be a non-empty string`;
115→  }
116→
117→  if (typeof entry.resource !== "string" || entry.resource.trim().length === 0) {
118→    return `authorization_details[${index}].resource is required and must be a non-empty string`;
119→  }
120→
121→  return undefined;
122→}
123→
124→// ---------------------------------------------------------------------------
125→// Pure Transformations
126→// ---------------------------------------------------------------------------
127→
128→/** Derive backward-compatible ActionSpec from first BrainAction */
129→export function deriveActionSpec(actions: BrainAction[]): ActionSpec {
130→  const first = actions[0];
131→  return {
132→    provider: "brain",
133→    action: first.action,
134→    params: { resource: first.resource },
135→  };
136→}
137→
138→/** Check if all actions are low-risk read operations */
139→export function isLowRiskReadAction(actions: BrainAction[]): boolean {
140→  return actions.every((a) => LOW_RISK_ACTIONS.has(a.action.toLowerCase()));
141→}
142→
143→// ---------------------------------------------------------------------------
144→// HTTP Handler Factory
145→// ---------------------------------------------------------------------------
146→
147→export type IntentSubmissionDeps = {
148→  lookupIdentity: LookupIdentity;
149→  lookupManager: LookupManager;
150→};
151→
152→export function createIntentSubmissionHandler(
153→  deps: ServerDependencies,
154→  identityDeps?: IntentSubmissionDeps,
155→): (request: Request) => Promise<Response> {
156→  const { surreal } = deps;
157→  const llmEvaluator = createLlmEvaluator(deps.extractionModel);
158→
159→  // Default identity lookup from SurrealDB when no explicit ports provided
160→  const lookupIdentity: LookupIdentity = identityDeps?.lookupIdentity ?? createSurrealIdentityLookup(surreal);
161→  const lookupManager: LookupManager = identityDeps?.lookupManager ?? createSurrealManagerLookup(surreal);
162→
163→  return async (request: Request): Promise<Response> => {
164→    let body: unknown;
165→    try {
166→      body = await request.json();
167→    } catch {
168→      return jsonError("Invalid JSON body", 400);
169→    }
170→
171→    const validation = validateIntentSubmission(body);
172→    if (!validation.valid) {
173→      return jsonError(validation.error, 400);
174→    }
175→
176→    const { data } = validation;
177→    const traceId = crypto.randomUUID();
178→
179→    try {
180→      // Check identity lifecycle before creating intent
181→      const identityCheck = await checkIdentityAllowed(
182→        data.identity_id,
183→        lookupIdentity,
184→        lookupManager,
185→      );
186→
187→      if (!identityCheck.allowed) {
188→        logInfo("intent.submission.identity_blocked", "Intent submission blocked by identity check", {
189→          identityId: data.identity_id,
190→          reason: identityCheck.reason,
191→          code: identityCheck.code,
192→        });
193→        return jsonError(identityCheck.reason, 403);
194→      }
195→
196→      const actionSpec = deriveActionSpec(data.authorization_details);
197→
198→      // Create intent record with new fields
199→      const intentId = await createIntent(surreal, {
200→        goal: data.goal,
201→        reasoning: data.reasoning,
202→        priority: data.priority ?? 0,
203→        action_spec: actionSpec,
204→        trace_id: traceId,
205→        requester: new RecordId("identity", data.identity_id),
206→        workspace: new RecordId("workspace", data.workspace_id),
207→        authorization_details: data.authorization_details,
208→        dpop_jwk_thumbprint: data.dpop_jwk_thumbprint,
209→      });
210→
211→      logInfo("intent.submission.created", "Intent created via OAuth submission", {
212→        intentId: intentId.id as string,
213→        traceId,
214→        workspaceId: data.workspace_id,
215→      });
216→
217→      // Transition to pending_auth to trigger evaluation
218→      const transitionResult = await updateIntentStatus(
219→        surreal,
220→        intentId.id as string,
221→        "pending_auth",
222→      );
223→
224→      if (!transitionResult.ok) {
225→        logError(
226→          "intent.submission.transition_failed",
227→          "Failed to transition intent to pending_auth",
228→          new Error(transitionResult.error),
229→          { intentId: intentId.id as string },
230→        );
231→        return jsonError("Failed to submit intent for evaluation", 500);
232→      }
233→
234→      // For low-risk read actions, trigger inline evaluation for auto-approve
235→      if (isLowRiskReadAction(data.authorization_details)) {
236→        try {
237→          const evaluation = await evaluateIntent({
238→            intent: {
239→              goal: data.goal,
240→              reasoning: data.reasoning,
241→              action_spec: actionSpec,
242→              requester: data.identity_id,
243→            },
244→            policy: {},
245→            llmEvaluator,
246→            timeoutMs: 10_000,
247→          });
248→
249→          const routing = routeByRisk(evaluation);
250→          const evaluationRecord = {
251→            ...evaluation,
252→            evaluated_at: new Date(),
253→          };
254→
255→          // For low-risk read actions, auto-approve unless explicitly rejected
256→          // (mirrors bridge exchange behavior: low-risk reads skip veto window)
257→          if (routing.route === "auto_approve" || (routing.route === "veto_window")) {
258→            await updateIntentStatus(surreal, intentId.id as string, "authorized", {
259→              evaluation: evaluationRecord,
260→            });
261→
262→            logInfo("intent.submission.auto_approved", "Low-risk read intent auto-approved", {
263→              intentId: intentId.id as string,
264→            });
265→
266→            return jsonResponse({
267→              intent_id: intentId.id as string,
268→              status: "authorized",
269→              trace_id: traceId,
270→            }, 201);
271→          }
272→        } catch (error) {
273→          logError(
274→            "intent.submission.inline_eval_failed",
275→            "Inline evaluation failed, falling back to async",
276→            error,
277→            { intentId: intentId.id as string },
278→          );
279→          // Fall through to pending_auth response
280→        }
281→      }
282→
283→      return jsonResponse({
284→        intent_id: intentId.id as string,
285→        status: "pending_auth",
286→        trace_id: traceId,
287→      }, 201);
288→    } catch (error) {
289→      logError("intent.submission.error", "Intent submission failed", error, {
290→        traceId,
291→      });
292→      return jsonError("Internal server error", 500);
293→    }
294→  };
295→}
296→
297→// ---------------------------------------------------------------------------
298→// SurrealDB Identity Lookups (adapter functions)
299→// ---------------------------------------------------------------------------
300→
301→import type { Surreal } from "surrealdb";
302→import type { ResolvedIdentity, ResolvedManager } from "./identity-lifecycle";
303→
304→type SurrealIdentityRow = {
305→  identityId: string;
306→  identityType: string;
307→  identityStatus?: string;
308→  managedBy?: string;
309→  revokedAt?: string;
310→};
311→
312→function createSurrealIdentityLookup(surreal: Surreal): LookupIdentity {
313→  return async (identityId: string) => {
314→    const rows = await surreal.query<[SurrealIdentityRow[]]>(
315→      `SELECT meta::id(id) AS identityId, type AS identityType, identity_status AS identityStatus, managed_by AS managedBy, revoked_at AS revokedAt FROM $identity;`,
316→      { identity: new RecordId("identity", identityId) },
317→    );
318→
319→    const row = rows[0]?.[0];
320→    if (!row) return undefined;
321→
322→    return {
323→      identityId: row.identityId,
324→      identityType: row.identityType as ResolvedIdentity["identityType"],
325→      identityStatus: (row.identityStatus ?? "active") as ResolvedIdentity["identityStatus"],
326→      managedBy: row.managedBy,
327→      revokedAt: row.revokedAt ? new Date(row.revokedAt) : undefined,
328→    };
329→  };
330→}
331→
332→function createSurrealManagerLookup(surreal: Surreal): LookupManager {
333→  return async (managerId: string) => {
334→    // Manager ID stored as raw string reference; look up identity by searching
335→    const rows = await surreal.query<[Array<{ identityStatus?: string }>]>(
336→      `SELECT identity_status AS identityStatus FROM identity WHERE meta::id(id) = $managerId LIMIT 1;`,
337→      { managerId },
338→    );
339→
340→    const row = rows[0]?.[0];
341→    if (!row) return undefined;
342→
343→    return {
344→      identityId: managerId,
345→      identityStatus: (row.identityStatus ?? "active") as ResolvedManager["identityStatus"],
346→    };
347→  };
348→}
