  1→/**
  2→ * Intent Node Acceptance Test Kit
  3→ *
  4→ * Extends the orchestrator-test-kit with intent-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/intents/:id/evaluate  (SurrealQL EVENT target)
  9→ *   POST /api/intents/:id/veto      (human veto)
 10→ *   MCP tools: create_intent, submit_intent, get_intent_status
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→
 14→// Re-export everything from orchestrator-test-kit
 15→export {
 16→  setupOrchestratorSuite,
 17→  createTestUser,
 18→  createTestWorkspace,
 19→  createReadyTask,
 20→  createTestProject,
 21→  getTestUserBearerToken,
 22→  fetchJson,
 23→  fetchRaw,
 24→  type OrchestratorTestRuntime,
 25→  type TestUser,
 26→  type TestUserWithToken,
 27→  type TestWorkspace,
 28→  type TestTask,
 29→  type TestProject,
 30→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 31→
 32→import {
 33→  fetchJson,
 34→  fetchRaw,
 35→  type TestUser,
 36→  type TestUserWithToken,
 37→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 38→
 39→// ---------------------------------------------------------------------------
 40→// Intent-Specific Types
 41→// ---------------------------------------------------------------------------
 42→
 43→export type IntentStatus =
 44→  | "draft"
 45→  | "pending_auth"
 46→  | "pending_veto"
 47→  | "authorized"
 48→  | "executing"
 49→  | "completed"
 50→  | "vetoed"
 51→  | "failed";
 52→
 53→export type ActionSpec = {
 54→  provider: string;
 55→  action: string;
 56→  params?: Record<string, unknown>;
 57→};
 58→
 59→export type BudgetLimit = {
 60→  amount: number;
 61→  currency: string;
 62→};
 63→
 64→export type EvaluationResult = {
 65→  decision: "APPROVE" | "REJECT";
 66→  risk_score: number;
 67→  reason: string;
 68→  evaluated_at: string;
 69→  policy_only: boolean;
 70→};
 71→
 72→export type IntentRecord = {
 73→  id: RecordId<"intent">;
 74→  goal: string;
 75→  reasoning: string;
 76→  status: IntentStatus;
 77→  priority: number;
 78→  action_spec: ActionSpec;
 79→  budget_limit?: BudgetLimit;
 80→  evaluation?: EvaluationResult;
 81→  veto_expires_at?: string;
 82→  veto_reason?: string;
 83→  error_reason?: string;
 84→  trace_id: string;
 85→  created_at: string;
 86→  updated_at?: string;
 87→};
 88→
 89→export type CreateIntentOptions = {
 90→  goal: string;
 91→  reasoning: string;
 92→  priority?: number;
 93→  action_spec: ActionSpec;
 94→  budget_limit?: BudgetLimit;
 95→  taskId?: string;
 96→};
 97→
 98→// ---------------------------------------------------------------------------
 99→// Domain Helpers -- Business Language Layer
100→// ---------------------------------------------------------------------------
101→
102→/**
103→ * Creates a draft intent directly in the database.
104→ * Used as a Given-step precondition for scenarios that start
105→ * with an intent already in draft status.
106→ */
107→export async function createDraftIntent(
108→  surreal: Surreal,
109→  workspaceId: string,
110→  requesterId: string,
111→  opts: CreateIntentOptions,
112→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
113→  const intentId = `intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
114→  const intentRecord = new RecordId("intent", intentId);
115→  const workspaceRecord = new RecordId("workspace", workspaceId);
116→  const requesterRecord = new RecordId("identity", requesterId);
117→
118→  const content: Record<string, unknown> = {
119→    goal: opts.goal,
120→    reasoning: opts.reasoning,
121→    status: "draft",
122→    priority: opts.priority ?? 50,
123→    action_spec: opts.action_spec,
124→    trace_id: `trace-${intentId}`,
125→    requester: requesterRecord,
126→    workspace: workspaceRecord,
127→    created_at: new Date(),
128→  };
129→
130→  if (opts.budget_limit) {
131→    content.budget_limit = opts.budget_limit;
132→  }
133→
134→  await surreal.query(`CREATE $intent CONTENT $content;`, {
135→    intent: intentRecord,
136→    content,
137→  });
138→
139→  // Link to originating task if provided
140→  if (opts.taskId) {
141→    const taskRecord = new RecordId("task", opts.taskId);
142→    await surreal.query(
143→      `RELATE $intent->triggered_by->$task SET created_at = time::now();`,
144→      { intent: intentRecord, task: taskRecord },
145→    );
146→  }
147→
148→  return { intentId, intentRecord };
149→}
150→
151→/**
152→ * Submits a draft intent for authorization.
153→ * Transitions draft -> pending_auth, which triggers the SurrealQL EVENT.
154→ */
155→export async function submitIntent(
156→  surreal: Surreal,
157→  intentId: string,
158→): Promise<void> {
159→  const intentRecord = new RecordId("intent", intentId);
160→  await surreal.query(
161→    `UPDATE $intent SET status = "pending_auth", updated_at = time::now();`,
162→    { intent: intentRecord },
163→  );
164→}
165→
166→/**
167→ * Queries the current status of an intent from the database.
168→ */
169→export async function getIntentStatus(
170→  surreal: Surreal,
171→  intentId: string,
172→): Promise<IntentStatus> {
173→  const intentRecord = new RecordId("intent", intentId);
174→  const rows = (await surreal.query(`SELECT status FROM $intent;`, {
175→    intent: intentRecord,
176→  })) as Array<Array<{ status: IntentStatus }>>;
177→  const result = rows[0]?.[0];
178→  if (!result) {
179→    throw new Error(`Intent ${intentId} not found`);
180→  }
181→  return result.status;
182→}
183→
184→/**
185→ * Queries the full intent record from the database.
186→ */
187→export async function getIntentRecord(
188→  surreal: Surreal,
189→  intentId: string,
190→): Promise<IntentRecord> {
191→  const intentRecord = new RecordId("intent", intentId);
192→  const rows = (await surreal.query(`SELECT * FROM $intent;`, {
193→    intent: intentRecord,
194→  })) as Array<Array<IntentRecord>>;
195→  const result = rows[0]?.[0];
196→  if (!result) {
197→    throw new Error(`Intent ${intentId} not found`);
198→  }
199→  return result;
200→}
201→
202→/**
203→ * Queries the evaluation result for an intent.
204→ */
205→export async function getIntentEvaluation(
206→  surreal: Surreal,
207→  intentId: string,
208→): Promise<EvaluationResult | undefined> {
209→  const record = await getIntentRecord(surreal, intentId);
210→  return record.evaluation;
211→}
212→
213→/**
214→ * Human vetoes an intent within the veto window.
215→ * Exercises the driving port: POST /api/intents/:id/veto
216→ */
217→export async function vetoIntent(
218→  baseUrl: string,
219→  user: TestUser | TestUserWithToken,
220→  workspaceId: string,
221→  intentId: string,
222→  reason: string,
223→): Promise<{ vetoed: boolean }> {
224→  const headers = "bearerHeaders" in user
225→    ? (user as TestUserWithToken).bearerHeaders
226→    : { "Content-Type": "application/json", ...user.headers };
227→
228→  return fetchJson<{ vetoed: boolean }>(
229→    `${baseUrl}/api/workspaces/${workspaceId}/intents/${intentId}/veto`,
230→    {
231→      method: "POST",
232→      headers,
233→      body: JSON.stringify({ reason }),
234→    },
235→  );
236→}
237→
238→/**
239→ * Lists intents in the governance feed that are pending human review.
240→ */
241→export async function listPendingIntents(
242→  surreal: Surreal,
243→  workspaceId: string,
