       WHERE workspace = \$workspace
         AND status = \$status
       ORDER BY created_at DESC
       LIMIT \$limit;\`,
      { workspace, status: filters.status, limit },
    );
    return rows;
  }

  const [rows] = await surreal.query<[IntentRecord[]]>(
    \`SELECT * FROM intent
     WHERE workspace = \$workspace
     ORDER BY created_at DESC
     LIMIT \$limit;\`,
    { workspace, limit },
  );
  return rows;
}
