  | "executing"
  | "completed"
  | "vetoed"
  | "failed";

export type ActionSpec = {
  provider: string;
  action: string;
  params?: Record<string, unknown>;
};

export type BudgetLimit = {
  amount: number;
  currency: string;
};

export type EvaluationResult = {
  decision: "APPROVE" | "REJECT";
  risk_score: number;
  reason: string;
  evaluated_at: string;
  policy_only: boolean;
};

export type IntentRecord = {
  id: RecordId<"intent">;
  goal: string;
  reasoning: string;
  status: IntentStatus;
  priority: number;
  action_spec: ActionSpec;
  budget_limit?: BudgetLimit;
  evaluation?: EvaluationResult;
  veto_expires_at?: string;
  veto_reason?: string;
  error_reason?: string;
  trace_id: RecordId<"trace">;
  created_at: string;
  updated_at?: string;
};

export type CreateIntentOptions = {
  goal: string;
  reasoning: string;
  priority?: number;
  action_spec: ActionSpec;
  budget_limit?: BudgetLimit;
  taskId?: string;
};

